ctx.lineCap = "round";
ctx.lineJoin = "round";

var C = {
  primary: "#2563eb",
  secondary: "#7c3aed",
  accent: "#f59e0b",
  highlight: "#10b981",
  danger: "#ef4444",
  panelBg: "rgba(250, 245, 235, 0.92)",
  panelBorder: "rgba(0,0,0,0.1)",
  text: "#1e293b",
  muted: "#64748b"
};

runtimeState.params = runtimeState.params || {};
if (runtimeState.params.sentenceLength == null) runtimeState.params.sentenceLength = 8;
if (runtimeState.params.modelDim == null) runtimeState.params.modelDim = 64;
if (runtimeState.params.numHeads == null) runtimeState.params.numHeads = 4;
if (runtimeState.params.temperature == null) runtimeState.params.temperature = 1.5;
if (runtimeState.params.numLayers == null) runtimeState.params.numLayers = 2;
if (runtimeState.params.focusToken == null) runtimeState.params.focusToken = 2;
if (runtimeState.params.maskCausal == null) runtimeState.params.maskCausal = true;
if (runtimeState.params.layerView == null) runtimeState.params.layerView = 0;

var p = runtimeState.pointer;
var w = canvas.width, h = canvas.height;

var N = Math.max(4, Math.min(16, Math.round(runtimeState.params.sentenceLength)));
var dModel = Math.max(16, Math.min(128, Math.round(runtimeState.params.modelDim)));
var heads = Math.max(1, Math.min(8, Math.round(runtimeState.params.numHeads)));
var temp = Math.max(0.5, Math.min(5.0, runtimeState.params.temperature));
var layers = Math.max(1, Math.min(6, Math.round(runtimeState.params.numLayers)));
var focus = Math.max(0, Math.min(N - 1, Math.round(runtimeState.params.focusToken)));
runtimeState.params.focusToken = focus;
runtimeState.params.layerView = Math.max(0, Math.min(layers - 1, Math.round(runtimeState.params.layerView)));

var left = w * 0.08, right = w * 0.92, topY = h * 0.44;
var span = right - left;
var tokenR = Math.max(14, Math.min(22, span / (N * 3.1)));

var tokens = [];
for (var i = 0; i < N; i++) {
  var x = left + (i / (N - 1 || 1)) * span;
  var y = topY + Math.sin(time * 1.3 + i * 0.45) * 2;
  tokens.push({ x: x, y: y });
}

function score(head, i, j, layer) {
  var base = Math.sin((i + 1) * 0.7 + (j + 1) * 1.11 + head * 1.9 + layer * 0.8 + time * 0.35) * 0.7;
  var near = 1.0 / (1 + Math.abs(i - j));
  var synt = Math.cos((i - j) * (0.8 + head * 0.1)) * 0.45;
  return base + near + synt;
}

var layer = runtimeState.params.layerView;
var headMats = [];
for (var hd = 0; hd < heads; hd++) {
  var arr = [];
  var maxv = -1e9;
  for (var j = 0; j < N; j++) {
    if (runtimeState.params.maskCausal && j > focus) { arr.push(0); continue; }
    var s = score(hd, focus, j, layer) * temp;
    arr.push(Math.exp(s));
    if (arr[j] > maxv) maxv = arr[j];
  }
  var sum = 0;
  for (var j2 = 0; j2 < N; j2++) sum += arr[j2];
  for (var j3 = 0; j3 < N; j3++) arr[j3] = sum > 0 ? arr[j3] / sum : 0;
  headMats.push(arr);
}

var avg = [];
for (var j4 = 0; j4 < N; j4++) {
  var t = 0;
  for (var hd2 = 0; hd2 < heads; hd2++) t += headMats[hd2][j4];
  avg.push(t / heads);
}

for (var j5 = 0; j5 < N; j5++) {
  var a = avg[j5];
  if (a <= 0) continue;
  ctx.strokeStyle = "rgba(124,58,237," + (0.12 + a * 0.75).toFixed(3) + ")";
  ctx.lineWidth = 1.2 + a * 5;
  ctx.beginPath();
  ctx.moveTo(tokens[focus].x, tokens[focus].y - tokenR);
  var mx = (tokens[focus].x + tokens[j5].x) * 0.5;
  var my = topY - 70 - Math.abs(focus - j5) * 7;
  ctx.quadraticCurveTo(mx, my, tokens[j5].x, tokens[j5].y - tokenR);
  ctx.stroke();
}

for (var i2 = 0; i2 < N; i2++) {
  var tkn = tokens[i2];
  var active = i2 === focus;
  ctx.beginPath();
  ctx.fillStyle = active ? C.accent : C.primary;
  ctx.arc(tkn.x, tkn.y, tokenR, 0, Math.PI * 2);
  ctx.fill();
  ctx.lineWidth = 2;
  ctx.strokeStyle = active ? "#b45309" : "rgba(37,99,235,0.35)";
  ctx.stroke();

  var pulse = 0.5 + 0.5 * Math.sin(time * 4 + i2);
  ctx.fillStyle = "rgba(16,185,129," + (0.12 + pulse * 0.28).toFixed(3) + ")";
  ctx.beginPath();
  ctx.arc(tkn.x, tkn.y, tokenR + 4 + pulse * 3, 0, Math.PI * 2);
  ctx.fill();

  if (p && p.clicked) {
    var dx = p.x - tkn.x, dy = p.y - tkn.y;
    if (dx * dx + dy * dy <= (tokenR + 6) * (tokenR + 6)) runtimeState.params.focusToken = i2;
  }
}

ctx.textAlign = "center";
ctx.fillStyle = C.text;
ctx.font = "11px system-ui, sans-serif";
for (var i3 = 0; i3 < N; i3++) ctx.fillText(("T" + i3), tokens[i3].x, topY + tokenR + 18);
ctx.fillText("TOKENS (STUDENTS) — CLICK ONE TO FOCUS", w * 0.5, topY - 110);
ctx.textAlign = "left";

var heatW = Math.min(w * 0.44, 520), heatH = Math.min(h * 0.28, 220);
var heatX = w * 0.08, heatY = h - heatH - 20;
var rows = Math.min(4, heads), cols = N;
var cellW = heatW / cols, cellH = heatH / rows;
for (var r = 0; r < rows; r++) {
  for (var c = 0; c < cols; c++) {
    var v = headMats[r][c];
    var alpha = 0.08 + v * 0.9;
    ctx.fillStyle = "rgba(124,58,237," + alpha.toFixed(3) + ")";
    if (runtimeState.params.maskCausal && c > focus) ctx.fillStyle = "rgba(239,68,68,0.35)";
    ctx.fillRect(heatX + c * cellW, heatY + r * cellH, cellW - 1, cellH - 1);
  }
}
ctx.strokeStyle = "rgba(0,0,0,0.12)";
ctx.lineWidth = 1.2;
ctx.strokeRect(heatX, heatY, heatW, heatH);

var panelX = 16, panelY = 16, panelW = Math.min(380, w * 0.44), panelH = 250;
ctx.fillStyle = C.panelBg;
ctx.strokeStyle = C.panelBorder;
ctx.lineWidth = 1;
ctx.beginPath(); ctx.roundRect(panelX, panelY, panelW, panelH, 12); ctx.fill(); ctx.stroke();

ctx.textAlign = "left";
ctx.fillStyle = C.muted;
ctx.font = "10px system-ui, sans-serif";
ctx.fillText("TRANSFORMER CONTROLS", panelX + 14, panelY + 18);

var sliders = [
  { key:"sentenceLength", label:"SENTENCE LENGTH (TOKENS)", min:4, max:16, step:1 },
  { key:"modelDim", label:"MODEL WIDTH (D_MODEL)", min:16, max:128, step:1 },
  { key:"numHeads", label:"ATTENTION HEADS", min:1, max:8, step:1 },
  { key:"temperature", label:"ATTENTION SHARPNESS (1/TEMP)", min:0.5, max:5.0, step:0.1 },
  { key:"numLayers", label:"NUMBER OF LAYERS", min:1, max:6, step:1 }
];
for (var s = 0; s < sliders.length; s++) {
  var sl = sliders[s];
  var y = panelY + 42 + s * 40;
  var x1 = panelX + 14, x2 = panelX + panelW - 14;
  var val = runtimeState.params[sl.key];
  var tnorm = (val - sl.min) / (sl.max - sl.min);
  var kx = x1 + tnorm * (x2 - x1);
  ctx.strokeStyle = "rgba(30,41,59,0.22)";
  ctx.lineWidth = 1.4;
  ctx.beginPath(); ctx.moveTo(x1, y); ctx.lineTo(x2, y); ctx.stroke();
  ctx.strokeStyle = C.primary;
  ctx.lineWidth = 3;
  ctx.beginPath(); ctx.moveTo(x1, y); ctx.lineTo(kx, y); ctx.stroke();
  ctx.fillStyle = C.primary;
  ctx.beginPath(); ctx.arc(kx, y, 6, 0, Math.PI * 2); ctx.fill();

  ctx.fillStyle = C.text;
  ctx.font = "11px system-ui, sans-serif";
  ctx.fillText(sl.label, x1, y - 10);
  ctx.font = "700 11px ui-monospace, monospace";
  ctx.fillText((Math.round(val * 10) / 10).toString(), x2 - 42, y - 10);

  if (p && p.down && p.x >= x1 - 8 && p.x <= x2 + 8 && p.y >= y - 10 && p.y <= y + 10) {
    var nt = Math.max(0, Math.min(1, (p.x - x1) / (x2 - x1)));
    var nv = sl.min + nt * (sl.max - sl.min);
    runtimeState.params[sl.key] = Math.round(nv / sl.step) * sl.step;
  }
}

var maskBtn = { x: panelX + 14, y: panelY + panelH - 34, w: 140, h: 22 };
if (p && p.clicked && p.x >= maskBtn.x && p.x <= maskBtn.x + maskBtn.w && p.y >= maskBtn.y && p.y <= maskBtn.y + maskBtn.h) {
  runtimeState.params.maskCausal = !runtimeState.params.maskCausal;
