ctx.fillStyle = C.text;
ctx.font = "11px system-ui, sans-serif";
ctx.fillText("CAUSAL MASK: " + (runtimeState.params.maskCausal ? "ON" : "OFF"), maskBtn.x + 10, maskBtn.y + 15);

var steps = [
  "Set Sentence Length to 6–8 and click a token to focus it.",
  "Increase Attention Sharpness so focus attends strongly to 1–2 tokens.",
  "Change Attention Heads from 1 to 4 and compare head patterns.",
  "Increase Model Width; vector capacity grows while attention shape stays.",
  "Raise Number of Layers to 4–6 and observe representation evolution."
];
if (runtimeState.params.stepIndex == null) runtimeState.params.stepIndex = 0;
var stepIndex = Math.max(0, Math.min(4, Math.round(runtimeState.params.stepIndex)));
runtimeState.params.stepIndex = stepIndex;

var sx = w - Math.min(420, w * 0.38) - 16, sy = 16, sw = Math.min(420, w * 0.38), sh = 170;
ctx.fillStyle = C.panelBg; ctx.strokeStyle = C.panelBorder;
ctx.beginPath(); ctx.roundRect(sx, sy, sw, sh, 12); ctx.fill(); ctx.stroke();
ctx.textAlign = "left";
ctx.fillStyle = C.muted; ctx.font = "10px system-ui, sans-serif";
