var words = msg.split(" "), line = "", yy = sy + 44;
for (var wi = 0; wi < words.length; wi++) {
  var test = line + words[wi] + " ";
  if (ctx.measureText(test).width > sw - 28) { ctx.fillText(line, sx + 14, yy); line = words[wi] + " "; yy += 16; }
  else line = test;
}
ctx.fillText(line, sx + 14, yy);

